def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.25:
            score += np.exp(-ratio) * 20
            for a in range(1, int(capacity) + 1):
                if a % 3 == 0 and a < item:
                    score += (a / capacity) * 4
                elif a % 5 == 0:
                    score -= np.sqrt(a) * 0.5
        elif 0.25 <= ratio < 0.5:
            for b in range(1, 6):
                temp = ((ratio ** b) * np.log1p(b + capacity % (b + 1))) * 7
                if b % 2 == 0:
                    temp = -temp
                score += temp
            if capacity > 10:
                for c in range(1, int(capacity // 3) + 1):
                    if c % 2 == 1 and int(item) % c == 0:
                        score += np.tanh(c) * 3
        elif 0.5 <= ratio <= 0.75:
            for d in range(1, int(np.ceil(ratio * 10)) + 1):
                mod_val = capacity % (d + 1)
                if mod_val == 0:
                    score += (d * ratio) ** 1.5
                else:
                    score -= (mod_val / (d + 1)) * 5
            score += (1 / (1 + np.exp(-5 * (ratio - 0.65)))) * 10
        elif 0.75 < ratio <= 1:
            for e in range(1, int(capacity) + 1):
                if e * ratio < capacity and e % 4 == 0:
                    score += np.log1p(e * ratio) * 2
            score += (1.5 - ratio) * 30
            if int(capacity) % 7 == 0:
                score *= 1.15
        else:
            penalty = 0
            int_ratio = int(np.floor(ratio))
            for f in range(1, int_ratio + 2):
                divisor = int_ratio if int_ratio != 0 else 1
                if divisor % f == 0:
                    penalty += f * ratio / (f + 1)
                else:
                    penalty -= np.sin(ratio * f)
            score = penalty * 12 + (ratio - 1) ** 3 * 40
            if ratio > 3:
                for g in range(1, 5):
                    h = capacity / (g + 0.5)
                    score += np.sin(h) * np.cos(ratio / g) * 6
        if capacity % 4 == 0 and ratio < 0.8:
            score *= 1.05
        if (int(capacity) + int(item)) % 6 == 0:
            score += 5
        if capacity > 100:
            large_cap_boost = 0
            for h in range(1, 11):
                large_cap_boost += np.sqrt(capacity % (h + 1) + h)
            score += large_cap_boost / 5
        priorities[i] = score
    min_priority = np.min(priorities[np.isfinite(priorities)])
    priorities = np.where(np.isfinite(priorities), priorities, min_priority + 300)
    return priorities
